sql:
SELECT corp_name 
FROM schools 
WHERE total_enrollment = (
    SELECT MAX(total_enrollment) 
    FROM schools
);

SELECT year, total_enrollment
FROM enrollment_years
ORDER BY year;

SELECT COUNT(year_id) AS total_enrollment_2023
FROM enrollment_years
WHERE year = 2023;

SELECT DISTINCT year
FROM enrollment_years
ORDER BY year DESC;

SELECT total_enrollment, year
FROM district_enrollments
WHERE year = 2023;

SELECT AVG(free_meals) AS average_free_meals
FROM meal_stats
WHERE year = 2023 AND free_meals_percentage > '40';

SELECT COUNT(*) AS total_schools
FROM enrollment_demographics ed
WHERE ed.year = 1 AND ed.white > 1000;

SELECT MIN(disabilities) 
FROM district_enrollments 
WHERE total_enrollment > 500 AND year = 2023;

